"use client";

import React from "react";
import { SelectSingle } from "@ui/molecules/SelectSingle/SelectSingle";
import { spacing, colors, radius } from "@tokens";
import { useTheme } from "@ui/context/ThemeProvider";
import {
    COMPONENT_TOKEN_OPTIONS,
    resolveTokenPath,
    type TokenOption,
} from "./componentTokenOptions";

type SemanticLike = {
    border?: { subtle?: string; default?: string };
    surface?: { default?: string };
};

type ComponentTokenRowProps = {
    label: string;
    value: string;
    onChange: (path: string) => void;
    /** Si se especifica, filtra las opciones a las que coincidan. */
    filterOptions?: (opt: TokenOption) => boolean;
};

export const ComponentTokenRow: React.FC<ComponentTokenRowProps> = ({
    label,
    value,
    onChange,
    filterOptions,
}) => {
    const { theme } = useTheme();
    const semantic = colors[theme].semantic as unknown as SemanticLike;
    const borderColor = semantic?.border?.subtle ?? semantic?.border?.default;
    const surfaceColor = semantic?.surface?.default;
    const options = filterOptions ? COMPONENT_TOKEN_OPTIONS.filter(filterOptions) : COMPONENT_TOKEN_OPTIONS;
    const resolvedColor = resolveTokenPath(colors[theme].semantic as Record<string, unknown>, value);

    return (
        <div
            style={{
                display: "grid",
                gridTemplateColumns: "minmax(0, 1fr) auto",
                alignItems: "center",
                gap: spacing[12],
                width: "100%",
                minWidth: 0,
                padding: `${spacing[12]} 0`,
                borderBottom: borderColor ? `1px solid ${borderColor}` : undefined,
            }}
        >
            <SelectSingle
                label={label}
                helperText={value || "—"}
                options={options}
                value={value}
                onChange={onChange}
            />
            <div
                style={{
                    width: spacing[40],
                    height: spacing[40],
                    flexShrink: 0,
                    borderRadius: radius.sm,
                    border: borderColor ? `1px solid ${borderColor}` : undefined,
                    backgroundColor: resolvedColor || surfaceColor,
                }}
                aria-hidden
            />
        </div>
    );
};
